{
  "terms": [
    {
      "term": "Ring Final Circuit",
      "simpleDefinition": "A circuit that starts at the consumer unit, connects to every outlet in a loop, and returns to the same starting point.",
      "anchor": "A continuous loop where current has two paths to reach any socket.",
      "misconception": "Thinking a ring circuit is just a long line; if the loop is broken, it becomes two radials and can easily overload."
    },
    {
      "term": "Radial Circuit",
      "simpleDefinition": "A circuit that runs from the consumer unit to the last point in a single line, like a branch on a tree.",
      "anchor": "A 'dead-end' circuit where power flows in only one direction from the source.",
      "misconception": "Assuming radials are only for low-power lighting; they are also used for high-power appliances like cookers."
    },
    {
      "term": "Wiring System",
      "simpleDefinition": "The combination of the specific cable type and the containment (like pipes or boxes) used to protect it.",
      "anchor": "The 'package' of the wire plus its protective housing.",
      "misconception": "Believing 'wiring system' only refers to the copper wire itself."
    },
    {
      "term": "SWA (Steel Wire Armoured)",
      "simpleDefinition": "A heavy-duty cable protected by a layer of steel wires to prevent mechanical damage.",
      "anchor": "The 'armoured' cable used for underground or industrial floor runs.",
      "misconception": "Thinking SWA is flexible enough for standard domestic wall chasing."
    },
    {
      "term": "MICC (Mineral Insulated Copper Clad)",
      "simpleDefinition": "A fireproof cable made of copper conductors inside a copper sheath, packed with mineral powder insulation.",
      "anchor": "The 'fireproof' cable used for emergency lighting and high-heat areas.",
      "misconception": "Assuming it is easy to install; it requires specialized seals to prevent moisture from ruining the powder insulation."
    },
    {
      "term": "Conduit",
      "simpleDefinition": "A tube or pipe, made of plastic or metal, used to house and protect individual cables.",
      "anchor": "A protective pipe for wires.",
      "misconception": "Thinking plastic conduit provides the same physical protection as steel conduit."
    },
    {
      "term": "Trunking",
      "simpleDefinition": "A rectangular enclosure with a removable lid used to organize and protect multiple cables.",
      "anchor": "A 'gutter' with a lid for managing large groups of cables.",
      "misconception": "Assuming you can fill trunking 100% full; space must be left for heat to escape."
    },
    {
      "term": "Hazardous Environment",
      "simpleDefinition": "An area where there is a high risk of explosion or fire due to the presence of gases, vapors, or dust.",
      "anchor": "A 'high-risk' zone requiring specialized explosion-proof wiring.",
      "misconception": "Thinking standard industrial equipment is safe enough for a hazardous zone."
    },
    {
      "term": "Agricultural Environment",
      "simpleDefinition": "Farming locations where cables are exposed to livestock, moisture, and corrosive chemicals like ammonia.",
      "anchor": "A 'farm' setting where equipment must resist damp and animal damage.",
      "misconception": "Assuming standard domestic 'Twin and Earth' cable is suitable for use in a barn."
    }
  ],
  "anchorPhrases": [
    "Ring final circuits form a continuous loop back to the source.",
    "Radial circuits run in a single line to the last point.",
    "A wiring system includes both the cable and its containment.",
    "SWA provides mechanical protection in tough environments.",
    "MICC is the primary choice for fire-resistant applications.",
    "Containment selection depends entirely on the installation environment."
  ],
